import requests
import hashlib


def createHash(password):
    return hashlib.sha256(password.encode('utf-8')).hexdigest()


def createToken(username, password):
    return username + "#" + createHash(password)


def verifyToken(token):
    return token and len(token.split("#")) == 2 \
           and token.split("#")[0] != "" \
           and token.split("#")[1] != ""


def login():
    username = input("Username: ")
    password = input("Password: ")

    userToken = createToken(username, password)

    print("New token created -", userToken)


def logout():
    print('You have logged out.')


def main(token):
    if not verifyToken(token):
        print("Invalid Token")
        return
    print('Logged in as', token.split("#")[0])


def protectedMethod():

    print('API Protected End Point')


if __name__ == '__main__':
    print('Welcome to Authenticate API!')
    while True:

        userInput = input(
            'Press l to login, p for a protected API endpoint and q to logout\n'
        )

        if len(userInput) > 0:
            if userInput[0].lower() == 'q':
                print('Logging out...')

                break

            elif userInput[0] in ['l', 'p']:

                if userInput.split()[1]:
                    token = login()

                    if not verifyToken(token):
                        print("Invalid Credentials")

                        continue

                else:
                    main(userInput.split())
            else:
                print('Invalid Input.')

        else:
            break

